    64→  absl::string_view path = request_headers_->getPathValue();
    65→  Http::Utility::QueryParamsMulti query =
    66→      Http::Utility::QueryParamsMulti::parseAndDecodeQueryString(path);
    67→  if (!query.data().empty()) {
    68→    return query;
